local TD = TD.td1madao["ydj_dst_td1madao"] local CONST = TD.CONST local sendMsgName = "jsonStr" local net_var_sim = Class(function(self, inst)     self.inst = inst     self.element = nil end) function net_var_sim:value()     return self.element end function net_var_sim:set(element)     self.element = element     return self.element end local myComponent = Class(function(self, inst)     self.inst = inst     local threadNum = 6     self.threadNum = threadNum     self.threadCanUse = threadNum - 1          self.playerTarget = TD.dst_r(function() return net_entity(inst.GUID, CONST.NOTIFY_EVENT .. "target", CONST.NOTIFY_EVENT .. "target") end, net_var_sim())          self:getTarget()     for i = 1, threadNum do         self[sendMsgName .. tostring(i)] = TD.dst_r(function() return net_string(inst.GUID, CONST.NOTIFY_EVENT .. tostring(i), CONST.NOTIFY_EVENT .. tostring(i)) end, net_var_sim())         if not TD.isServer() then             self.inst:ListenForEvent(CONST.NOTIFY_EVENT .. tostring(i), function()                 local param = self:player_getJsonObj(i)                 if not param or not param.name then                     return                 end                 local name = param.name                 local client = TD.G.CLIENT_FN                 if not client or not name then                     return                 end                 param.inst = self.inst                 if param.thePlayerOnly and self.inst ~= TD.GetPlayer() then                     return                 end                 TD.debug(self:common_getStr(i), false)                 if client[name] then                     client[name](param)                 end             end)         end     end end) function myComponent:setTarget(target)     if target ~= nil then         self.playerTarget:set(target)     end end function myComponent:getTarget()     local target = self.playerTarget:value()     if target ~= nil then                  TD.server(function()             self.playerTarget:set(nil)         end, function()                          TD.serverCall(TD.holder("%s_clean_player_target"), {})         end)     end     return target end local taskName = TD.holder("%s_proessTarget") function myComponent:proessTarget(fn)     if TD.isFn(fn) then         TD.ctm(self.inst, function(comp)             comp:common_period(0.1, function()                                  local target = self:getTarget()                 if target ~= nil then                     fn(target)                     comp:common_clean(taskName)                     comp:common_clean(taskName .. "cleaner")                 end             end, taskName, 3)         end)     end end function myComponent:server_send(name, param, allPlayer)     self:server_setJsonObj(name, param, allPlayer) end function myComponent:server_setJsonObj(name, obj, allPlayer)     if not obj or not name then         return     end     obj.name = name     if not allPlayer then         obj.thePlayerOnly = true     end     if obj.player then         obj.player = nil     end     if obj.inst then         obj.inst = nil     end          if TD.ds() then                  obj.thePlayerOnly = false         self:server_callSelf(obj, name)         return     end          if TD.isPlayer(self.inst) then                  if allPlayer then             self:server_callOthers(obj)         end                  self:server_callSelf(obj, name)     else                  if self.inst and self.inst.HasTag and not self.inst:HasTag("player") then                          self:server_callOthers(obj)                          self:server_callSelf(obj, name)         else             self:server_callOthers(obj)                          if allPlayer then                                                   self:server_callSelf(obj, name)             end         end     end end function myComponent:server_callSelf(obj, name)          if not TD.GetPlayer() or not (TD.GetPlayer().components) then         return     end     local client = TD.G.CLIENT_FN     if not client or not name then         return     end               obj.inst = self.inst     if obj.thePlayerOnly and self.inst ~= TD.GetPlayer() then         return     end     if client[name] then         client[name](obj)     end end function myComponent:server_callOthers(obj)          local sendSuccess = false     for i = 1, self.threadCanUse do         if self["block" .. tostring(i)] == nil then                          local jsonObj = self:server_getJsonObj(i)             local reverter = jsonObj.re             if not reverter or reverter == 1 then                 obj.re = 2             else                 obj.re = 1             end                          local jsonStrMsg = TD.encode(obj)                          TD.debug(jsonStrMsg, true, self.inst)                          self["block" .. tostring(i)] = TD.latter(self.inst, 0.1, function()                                  if self["block" .. tostring(i)] then                     if self["block" .. tostring(i)].Cancel then                         self["block" .. tostring(i)]:Cancel()                     end                 end                 self["block" .. tostring(i)] = nil             end)                          self[sendMsgName .. tostring(i)]:set(jsonStrMsg)             sendSuccess = true             break;         end     end     if not sendSuccess then                  local i = self.threadNum                  local jsonObj = self:server_getJsonObj(i)         local reverter = jsonObj.re         if not reverter or reverter == 1 then             obj.re = 2         else             obj.re = 1         end                  local jsonStrMsg = TD.encode(obj)                  TD.debug(jsonStrMsg, true, self.inst)                  self["block" .. tostring(i)] = TD.latter(self.inst, 0.1, function()                          if self["block" .. tostring(i)] then                 if self["block" .. tostring(i)].Cancel then                     self["block" .. tostring(i)]:Cancel()                 end             end             self["block" .. tostring(i)] = nil         end)                  self[sendMsgName .. tostring(i)]:set(jsonStrMsg)     end end function myComponent:common_getStr(num)     return tostring(self[sendMsgName .. tostring(num)]:value()) end function myComponent:common_getJsonObj(num)     local returnResult     TD.try(function()         local res = self:common_getStr(num)         returnResult = TD.decode(res)     end)     return returnResult or {} end function myComponent:player_getJsonObj(num)     return self:common_getJsonObj(num) end function myComponent:server_getJsonObj(num)     return self:common_getJsonObj(num) end return myComponent 